1	import { describe, it, expect } from "vitest";
2	import { render, screen } from "@testing-library/react";
3	import { ProbabilityBar } from "@/components/ui/ProbabilityBar";
4	import { Spinner, LoadingPage, ErrorMessage } from "@/components/ui/Spinner";
5	import { StatusBadge } from "@/components/ui/StatusBadge";
6	
7	describe("ProbabilityBar", () => {
8	  const outcomes = [
9	    { id: "yes", name: "Yes" },
10	    { id: "no", name: "No" },
11	  ];
12	  const marginals: Record<string, number> = { yes: 0.65, no: 0.35 };
13	
14	  it("renders outcome names and formatted probabilities", () => {
15	    render(<ProbabilityBar outcomes={outcomes} marginals={marginals} />);
16	    expect(screen.getByText(/Yes/)).toBeInTheDocument();
17	    expect(screen.getByText(/65\.0%/)).toBeInTheDocument();
18	    expect(screen.getByText(/No/)).toBeInTheDocument();
19	    expect(screen.getByText(/35\.0%/)).toBeInTheDocument();
20	  });
21	
22	  it("uses title attributes with name: probability format", () => {
23	    render(<ProbabilityBar outcomes={outcomes} marginals={marginals} />);
24	    expect(screen.getByTitle("Yes: 65.0%")).toBeInTheDocument();
25	    expect(screen.getByTitle("No: 35.0%")).toBeInTheDocument();
26	  });
27	
28	  it("missing marginal entries default to 0%", () => {
29	    render(<ProbabilityBar outcomes={outcomes} marginals={{}} />);
30	    expect(screen.getByTitle("Yes: 0.0%")).toBeInTheDocument();
31	    expect(screen.getByTitle("No: 0.0%")).toBeInTheDocument();
32	    expect(screen.getByText(/Yes 0\.0%/)).toBeInTheDocument();
33	  });
34	
35	  it("empty outcomes array renders without crashing", () => {
36	    const { container } = render(<ProbabilityBar outcomes={[]} marginals={{}} />);
37	    expect(container).toBeTruthy();
38	  });
39	});
40	
41	describe("Spinner", () => {
42	  it("renders an SVG element", () => {
43	    const { container } = render(<Spinner />);
44	    expect(container.querySelector("svg")).toBeInTheDocument();
45	  });
46	
47	  it("default size is 24x24", () => {
48	    const { container } = render(<Spinner />);
49	    const svg = container.querySelector("svg")!;
50	    expect(svg.getAttribute("width")).toBe("24");
51	    expect(svg.getAttribute("height")).toBe("24");
52	  });
53	
54	  it("custom size prop controls width/height attributes", () => {
55	    const { container } = render(<Spinner size={48} />);
56	    const svg = container.querySelector("svg")!;
57	    expect(svg.getAttribute("width")).toBe("48");
58	    expect(svg.getAttribute("height")).toBe("48");
59	  });
60	});
61	
62	describe("LoadingPage", () => {
63	  it("renders a Spinner with size 32", () => {
64	    const { container } = render(<LoadingPage />);
65	    const svg = container.querySelector("svg")!;
66	    expect(svg).toBeInTheDocument();
67	    expect(svg.getAttribute("width")).toBe("32");
68	    expect(svg.getAttribute("height")).toBe("32");
69	  });
70	});
71	
72	describe("ErrorMessage", () => {
73	  it("renders the provided message text", () => {
74	    render(<ErrorMessage message="Something broke" />);
75	    expect(screen.getByText("Something broke")).toBeInTheDocument();
76	  });
77	
78	  it("has danger-colored styling", () => {
79	    render(<ErrorMessage message="fail" />);
80	    const el = screen.getByText("fail");
81	    expect(el.style.color).toBe("var(--color-danger)");
82	  });
83	});
84	
85	describe("StatusBadge", () => {
86	  it("renders status text", () => {
87	    render(<StatusBadge status="active" />);
88	    expect(screen.getByText("active")).toBeInTheDocument();
89	  });
90	
91	  it("different statuses produce different border colors", () => {
92	    const { rerender } = render(<StatusBadge status="active" />);
93	    const activeEl = screen.getByText("active");
94	    const activeBorder = activeEl.style.border;
95	
96	    rerender(<StatusBadge status="resolved" />);
97	    const resolvedEl = screen.getByText("resolved");
98	    const resolvedBorder = resolvedEl.style.border;
99	
100	    expect(activeBorder).not.toBe(resolvedBorder);
101	    expect(activeBorder).toContain("var(--color-active)");
102	    expect(resolvedBorder).toContain("var(--color-resolved)");
103	  });
104	
105	  it("text is in original case in DOM (CSS handles uppercase)", () => {
106	    render(<StatusBadge status="active" />);
107	    const el = screen.getByText("active");
108	    expect(el.textContent).toBe("active");
109	    expect(el.style.textTransform).toBe("uppercase");
110	  });
111	});
